<template>
  <VContainer fluid>
    <VRow>
      <VCol cols="6">
        <VTextField v-model="searchKey" label="Nama atau Kode Barang"> </VTextField>
      </VCol>

      <VCol class="flex items-center" cols="1">
        <VBtn color="primary" @click="clickFilter">Filter</VBtn>
      </VCol>
      <VCol class="flex items-center" cols="1">
        <VBtn color="primary" to="/formbarang?id=new">New</VBtn>
      </VCol>
    </VRow>
    <VRow>
      <VCol cols="12">
        <VDataTable :headers="headers" :items="listBarang">
          <template v-slot:item.id="{ item }">
            <div>
              <VBtn :to="`/formbarang?id=${item.columns.id}`" size="x-small" variant="text"
                >Edit
              </VBtn>
              <VBtn :icon="mdiIcon.mdiClose" size="x-small" @click="hapusBarang(item.id)"></VBtn>
            </div>
          </template>
        </VDataTable>
      </VCol>
    </VRow>
  </VContainer>
</template>

<script setup>
import { VDataTable } from 'vuetify/labs/VDataTable'
import * as mdiIcon from '@mdi/js'
import { useBarangStore } from '@/stores/barangStore'
import { storeToRefs } from 'pinia'

const { axiosGet } = useAppStore()
const barangStore = useBarangStore()
const { listBarang, searchKey } = storeToRefs(barangStore)

const headers = ref([
  { title: 'Nama Barang', key: 'nama' },
  { title: 'Barcode', key: 'barcode' },
  { title: 'Harga Satuan', key: 'hargaJual', align: 'end' },
  { title: 'Jumlah', key: 'qty', align: 'end' },
  { title: 'Penjualan', key: 'saleQty', align: 'end' },
  { title: 'action', key: 'id', align: 'end' }
])

const clickFilter = () => {
  searchBarang()
}

const searchBarang = () => {
  axiosGet('/barang/search', { params: { key: searchKey.value } }).then((response) => {
    if (response.status == 200) {
      barangStore.setListBarang(response.data.data)
    }
  })
}

const hapusBarang = (id) => {
  const updatedList = listBarang.value.filter((barang) => barang.id !== id)
  barangStore.setListBarang(updatedList)
}

onMounted(() => {
  searchBarang()
})
</script>
